```javascript
function solve(nums, k) {
    let prefixMod = 0;
    let modCount = new Map();
    modCount.set(0, 1);
    let minSum = Infinity;

    for (let num of nums) {
        prefixMod = (prefixMod + num) % k;
        if (modCount.has(prefixMod)) {
            minSum = Math.min(minSum, (prefixMod + k) % k);
        } else {
            modCount.set(prefixMod, 1);
        }
    }

    return minSum;
}
