function solve(nums, k) {
    let total = 0;
    let mod = 0;
    let minSum = Infinity;

    for (let num of nums) {
        total += num;
        mod = (mod + num) % k;

        // If mod is 0, we can remove this subarray
        if (mod === 0) {
            minSum = Math.min(minSum, total);
            total = 0;
            mod = 0;
        } else {
            // Keep track of the current sum and mod
            minSum = Math.min(minSum, total);
        }
    }

    return minSum;
}
