function solve(nums, k) {
    let total = 0;
    let mod = 0;
    let minSum = Infinity;

    for (const num of nums) {
        total += num;
        mod = (mod + num) % k;

        // If mod is 0, we can remove this subarray
        if (mod === 0) {
            minSum = Math.min(minSum, total);
            total = 0;
            mod = 0;
        }
    }

    // Check if there is a subarray that can be removed at the end
    if (mod === 0) {
        minSum = Math.min(minSum, total);
    }

    // The minimal possible sum is the total sum minus the maximum possible sum of removed subarrays
    return total - minSum;
}
